sql:
SELECT SUM(followers_count)
FROM tweets
WHERE sentiment_score > (SELECT AVG(sentiment_score) FROM tweets WHERE location = 'India');

SELECT username
FROM tweets
WHERE sentiment_score >= 0;

external_knowledge:
- 'insightful Analysts' refers to users with the role 'Analyst' who have a higher sentiment score than average;
- 'sharing unique thoughts' implies tweets that are not retweets;
- 'exceed the usual emotional impact' indicates a sentiment score greater than the average sentiment score of all tweets.

sql:
SELECT hashtag, MAX(popularity_score) AS max_popularity_score
FROM hashtags
GROUP BY hashtag;

external_knowledge:
- "beacons" metaphorically refer to the hashtags that stand out the most; 
- "shining the brightest" metaphorically indicates the hashtags with the highest popularity scores;
- "glow" is a metaphor for the popularity score of a hashtag.

sql:
SELECT hashtag, popularity_score 
FROM hashtags 
WHERE popularity_score = (SELECT MAX(popularity_score) FROM hashtags);

external_knowledge:
"Influential users" refer to users with over 10,000 followers;
"Widely discussed" means the tweet has over 100 likes, retweets, and replies;
"Trending hashtag" indicates a hashtag with a popularity score over 50.

sql:
SELECT tweet_id, username, tweet_content, sentiment_score 
FROM tweets 
WHERE sentiment_score < -0.5 OR sentiment_score > 0.5;

SELECT tweet_id, tweet_content
FROM tweets
WHERE retweet_count > (
    SELECT AVG(retweet_count)
    FROM tweets
);

SELECT hashtag
FROM hashtags
WHERE popularity_score > 500;
